import urllib.parse

def login_redirect(current_url, login_url, redirect_param='next'):
    """
    Generates a login URL that includes a redirect back to the user's
    intended destination after successful authentication.

    Args:
        current_url (str): The URL the user was trying to access before being
                           redirected to the login page.
        login_url (str): The base URL of your login page.
        redirect_param (str): The name of the URL parameter used to pass
                              the redirect destination (e.g., 'next' or 'redirect_to').

    Returns:
        str: The full login URL with the redirect parameter appended.
    """
    parsed_login_url = urllib.parse.urlparse(login_url)
    query_params = dict(urllib.parse.parse_qsl(parsed_login_url.query))

    query_params[redirect_param] = current_url

    new_query_string = urllib.parse.urlencode(query_params)

    # Reconstruct the URL with the new query string
    redirect_url = urllib.parse.urlunparse(
        parsed_login_url._replace(query=new_query_string)
    )

    return redirect_url